                <UserPlus size={18} />
                <span className="hidden sm:inline">Add Player</span>
              </button>
            </div>
          </div>
        </header>

        {/* Floating Current Turn Bar */}
        <div className="turn-indicator-sticky bg-[#0c1a26]/95 backdrop-blur-md border-b-8 border-amber-600 py-3">
